// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');

let tasksStore = [];

async function createTask(projectId, description) {
  const task = {
    id: randomUUID(),
    projectId,
    description,
    status: 'todo',
  };
  tasksStore.push(task);
  return task;
}

async function getAllTasks(projectId) {
  return tasksStore.filter(task => task.projectId === projectId);
}

async function updateTaskStatus(projectId, taskId, status) {
  const task = tasksStore.find(t => t.id === taskId && t.projectId === projectId);
  if (task) {
    task.status = status;
  }
  return task;
}

module.exports = {
  createTask,
  getAllTasks,
  updateTaskStatus,
};

// src/modules/members/routes.js
const express = require('express');
const router = express.Router();
const membersService = require('../service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Payload must include both userId and role');
  }

  try {
    const member = await membersService.addMember(req.params.projectId, { userId, role });
    if (!member) {
      return sendError(res, 409, 'DUPLICATE_MEMBER', 'Member already exists in this project');
    }
    res.status(201).json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const errors = require('../../lib/errors');

let membersStore = [];

async function addMember(projectId, member) {
  const existingMember = membersStore.find(m => m.projectId === projectId && m.userId === member.userId);
  if (existingMember) {
    return null;
  }

  const newMember = {
    id: randomUUID(),
    projectId,
    ...member,
  };
  membersStore.push(newMember);
  return newMember;
}

module.exports = {
  addMember,
};

